<template><el-card><template #header><div class="head"><b>数据导出记录</b><el-button v-if="user.hasPermission('data:export:sensitive:apply')" type="warning" @click="$router.push('/exports/sensitive/create')">申请敏感导出</el-button></div></template><el-form inline><el-form-item label="模块"><el-select v-model="q.module" clearable><el-option v-for="x in modules" :key="x" :value="x"/></el-select></el-form-item><el-form-item label="类型"><el-select v-model="q.exportType" clearable><el-option value="NORMAL_MASKED"/><el-option value="SENSITIVE_APPROVED"/></el-select></el-form-item><el-button @click="load">查询</el-button></el-form><el-table :data="rows"><el-table-column prop="exportNo" label="导出编号"/><el-table-column prop="exportModule" label="模块"/><el-table-column prop="exportType" label="类型"/><el-table-column prop="rowCount" label="行数"/><el-table-column prop="status" label="状态"/><el-table-column prop="createdAt" label="创建时间"/><el-table-column label="操作"><template #default="{row}"><el-button link @click="$router.push('/exports/'+row.exportLogId)">详情</el-button></template></el-table-column></el-table></el-card></template>
<script setup>import{ref,reactive,onMounted}from'vue';import{listExports}from'../../api/exports';import{useUserStore}from'../../stores/user';const user=useUserStore(),rows=ref([]),q=reactive({module:'',exportType:'',page:0,size:30}),modules=['PERSON','HOUSEHOLD','MIGRATION','RESIDENCE_ARCHIVE','CANCELLATION','FLOATING_POPULATION','RESIDENCE_PERMIT','OPERATION_LOG'];async function load(){const r=await listExports(q);rows.value=r.content||[]}onMounted(load)</script><style scoped>.head{display:flex;justify-content:space-between}</style>
